const origin = (body as any).origin;
    const destination = (body as any).destination;
    const [costData, etaData] = await Promise.all([
      vendorFetch<{ cost_estimates: any[] }>({
        bearer,
        method: "GET",
        path: "/cost",
        query: {
          start_lat: origin.latitude,
          start_lng: origin.longitude,
          end_lat: destination.latitude,
          end_lng: destination.longitude,
        },
      }),
      vendorFetch<{ eta_estimates: any[] }>({
        bearer,
        method: "GET",
        path: "/eta",
        query: { lat: origin.latitude, lng: origin.longitude },
      }),
    ]);
    const etaByRideType: Record<string, number> = {};
    for (const e of etaData.eta_estimates ?? []) etaByRideType[e.ride_type] = e.eta_seconds;
    const offers = (costData.cost_estimates ?? []).map((c: any) => ({
      product_id: c.ride_type,
      product_name: c.display_name,
      low_estimate: c.estimated_cost_cents_min / 100,
      high_estimate: c.estimated_cost_cents_max / 100,
      currency_code: c.currency,
      pickup_estimate_minutes: etaByRideType[c.ride_type] ? Math.ceil(etaByRideType[c.ride_type] / 60) : null,
      duration_seconds: c.estimated_duration_seconds,
      distance_meters: c.estimated_distance_miles ? Math.round(c.estimated_distance_miles * 1609.34) : null,
      surge_multiplier: c.primetime_percentage ? 1 + Number(c.primetime_percentage.replace("%", "")) / 100 : 1.0,
    }));
    return NextResponse.json({ offers });

if ((body as any).simulate) {
      return NextResponse.json({
        ride_id: `simulate:${(body as any).ride_type}`,
        status: "processing",
        ride_type: (body as any).ride_type,
        simulated: true,
      });
    }
    const result = await vendorFetch<{ ride_id: string; status: string; ride_type?: string }>({
      bearer,
      method: "POST",
      path: "/rides",
      body: {
        ride_type: (body as any).ride_type,
        origin: { lat: (body as any).origin.latitude, lng: (body as any).origin.longitude },
        destination: { lat: (body as any).destination.latitude, lng: (body as any).destination.longitude },
      },
    });
    return NextResponse.json({ ride_id: result.ride_id, status: result.status, ride_type: result.ride_type });

const result = await vendorFetch<{ ride_history: any[] }>({
      bearer,
      method: "GET",
      path: "/rides",
      query: { limit: Math.min((body as any).limit ?? 10, 50) },
    });
    const rides = (result.ride_history ?? []).map((r: any) => ({
      ride_id: r.ride_id,
      status: r.status,
      ride_type: r.ride_type,
      requested_at: r.requested_at,
      origin: r.origin?.address ?? null,
      destination: r.destination?.address ?? null,
      distance_meters: r.distance_miles ? Math.round(r.distance_miles * 1609.34) : null,
      duration_seconds: r.duration_seconds ?? null,
      price: r.price ? { total: r.price.amount / 100, currency_code: r.price.currency } : null,
    }));
    return NextResponse.json({ rides, count: rides.length });
